var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이곳이 페리어가 자주 찾는다는 찻집이군요.","JPN":"この喫茶店が、フェリエーのお気に入りなんですね。","ENG":"So this is the tea house that you frequent.","TWN":"這裡就是佩里常來的茶館啊。"},"stage":{"bg":"CAFE","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇습니다. 좋은 찻잎과 아늑한 분위기를 갖춘 숨겨진 명소죠.","JPN":"はい。いい茶葉と穏やかな雰囲気を兼ね備えた隠れ家です。","ENG":"That's right. It's a hidden gem, with the finest tea leaves and a cozy atmosphere.","TWN":"是的。茶葉好，環境雅致，是個不為人所知的好地方。"},"stage":{"bg":"CAFE","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨께서도 마음에 들어하실 것이라고 자부합니다.","JPN":"きっと、お嬢様もお気に召すはずです。","ENG":"I'm confident that you'll find it to your liking as well.","TWN":"我敢保證，小姐您也一定會喜歡的。"},"stage":{"bg":"CAFE","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"잘됐네요. 물벼룩을 기관에 들인 뒤로 한동안 쉬지 못했죠.","JPN":"ちょうどいいですわ。ミジンコが機関に入って以来、ろくに休んでいないので。","ENG":"That's good to hear. I've hardly had a break ever since we took in the Water Flea.","TWN":"正好，自從水蚤進入機關後，我就有很長的時間沒有好好休息了。"},"stage":{"bg":"CAFE","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"음......?","JPN":"……うん？","ENG":"Huh?","TWN":"嗯……？"},"stage":{"bg":"CAFE","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"힉?!","JPN":"ひっ！？","ENG":"Eep?!","TWN":"噫？！"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"왜 그러시죠, 손님? 홍차가 마음에 안 드시나요?","JPN":"お客様、どうされましたか？　紅茶に何か問題でも？","ENG":"What's wrong, ma'am? Is the tea not to your liking?","TWN":"怎麼了，客人？您對紅茶不滿意嗎？"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아, 아뇨! 무척 마음에 들어요! 그런데 제가 뭘 하고 있었죠?!","JPN":"い、いいえ！　とても素晴らしい紅茶ですわ！　ところで今、私は何をしてましたの？","ENG":"N-no! It's very nice! But what was I doing just now?","TWN":"啊，不是！我非常滿意！不過我剛剛在做什麼呢？！"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"방금까지 차를 마시면서 독서 중이셨습니다만......","JPN":"先ほどまで、お茶を楽しみながら読書をなさってましたが……","ENG":"You were reading and drinking tea...","TWN":"直到剛才，您都在一邊喝茶，一邊看書……"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그, 그랬죠! 갑자기 급한 용무가 생겨서 그러는데 남은 차는 포장해 주세요!","JPN":"そ、そうでしたわ！　急な用事を思い出したので、残りの紅茶は持ち帰りますわね！","ENG":"O-oh, right! Sorry, but I've got an urgent matter to attend to. I'll take the rest in a doggy bag please!","TWN":"對、沒錯！我突然有急事，請將剩下的茶葉幫我打包起來！"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"손님...... 한 번 우린 티백은 포장해 드리기가 곤란합니다.","JPN":"お客様……一度お茶を淹れたティーバッグはお包みできません。","ENG":"Ma'am... We can't exactly put a tea bag in a doggy bag once it's been brewed...","TWN":"客人……泡過一次的茶包是不能打包的。"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기껏 좋은 가게에 와서 CTC 제법으로 만든 찻잎을 고르다니, 홍차에는 문외한이네요.","JPN":"せっかく素敵なお店に来たのに、CTC製法の茶葉を選ぶなんて。\\n紅茶に関しては、素人同然ですわね。","ENG":"You come to a posh establishment like this and choose a CTC tea? You're clueless about tea, aren't you?","TWN":"難得到了一家這麼好的店裡，居然選了CTC製法做成的茶葉。看來在紅茶方面，妳是個外行人呢。"},"stage":{"bg":"CAFE","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"또 잘난 척이네요! 무슨 찻잎을 고를지는 제 취향이죠!","JPN":"また偉そうに！　どんな茶葉を選ぼうと、私の勝手ですわ！","ENG":"There you go again, bragging like a snob! I've got every right to pick the tea I like!","TWN":"又一副跩樣！選什麼茶葉是我的自由！"},"stage":{"bg":"CAFE","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......저, 그런데 CTC가 무슨 뜻이에요?","JPN":"……あの、ところでCTCって何ですの？","ENG":"Uh, by the way... What does CTC stand for?","TWN":"……呃，不過，那個CTC是什麼意思？"},"stage":{"bg":"CAFE","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"부수고, 찢고, 비빈다는 말의 약자랍니다. 품질이 제각각인 찻잎으로 적당한 수준의 맛을 낼 때 쓰이죠.","JPN":"Crush＝つぶす/Tear＝裂く/Curl＝丸めるの略です。\\n品質がまばらな茶葉で、ほどほどの味を作り出す際に使われます。","ENG":"It stands for crush, tear, and curl. It's a process used to package tea leaves of inconsistent quality.","TWN":"是碾碎、撕開、揉搓意思的縮寫。是品質參差不齊的茶葉所混合，味道等級一般的茶。"},"stage":{"bg":"CAFE","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"다시 말해, 이런 전문점이 아니라도 어디서나 구할 수 있는 공산품이란 뜻이에요.","JPN":"簡単に言えば、このような専門店じゃなくても手に入る、大量生産による商品です。","ENG":"In other words, it's a mass-produced product you can find anywhere without having to visit a dedicated tea house like this.","TWN":"換句話說，就算不來這種專門店，隨便在哪裡都能喝到的工業製品，。"},"stage":{"bg":"CAFE","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"맥크레디 양이라면 보나마나 점원에게 추천 받는 대신 자기 눈에 띄는 걸 고르고 봤겠죠.","JPN":"マクレディーさんなら、店員さんにおすすめを聞く代わりに、自分で選んだのでしょう。","ENG":"It's likely you simply picked out what you were familiar with instead of asking the staff for recommendations, Ms. MacCready.","TWN":"麥克雷迪小姐的話，比起店員為妳推薦，是自己選了個顯眼的東西吧。"},"stage":{"bg":"CAFE","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};